  1	import {
  2	  Dropdown,
  3	  DropdownItem,
  4	  DropdownList,
  5	  FormGroup,
  6	  MenuToggle,
  7	  MenuToggleElement,
  8	} from '@patternfly/react-core';
  9	import React from 'react';
 10	import { useLocalStorage } from '../hooks/useLocalStorage';
 11	import { TimeRange } from '../logs.types';
 12	import { TestIds } from '../test-ids';
 13	import {
 14	  CUSTOM_TIME_RANGE_KEY,
 15	  formatTimeRange,
 16	  timeOptionKeyFromRange,
 17	  timeRangeFromDuration,
 18	  timeRangeOptions,
 19	} from '../time-range';
 20	import { TimeRangeSelectModal } from './time-range-select-modal';
 21	import { useTranslation } from 'react-i18next';
 22	
 23	const DEFAULT_DURATION_KEY = '1h';
 24	const STORED_TIME_RANGE_KEY = 'logging-view-plugin.time-range';
 25	
 26	interface TimeRangeDropdownProps {
 27	  value?: TimeRange;
 28	  onChange?: (timeRange: TimeRange) => void;
 29	  isDisabled?: boolean;
 30	  timezone?: string;
 31	}
 32	
 33	const getSelectedOptionIndex = ({
 34	  storedTimeRange,
 35	  timeRangeValue,
 36	}: {
 37	  storedTimeRange?: TimeRange | null;
 38	  timeRangeValue?: TimeRange;
 39	}): number => {
 40	  let durationKey: string | undefined;
 41	
 42	  if (timeRangeValue) {
 43	    durationKey = timeOptionKeyFromRange(timeRangeValue);
 44	  }
 45	
 46	  if (storedTimeRange) {
 47	    durationKey = timeOptionKeyFromRange(storedTimeRange);
 48	  }
 49	
 50	  if (!durationKey) {
 51	    durationKey = DEFAULT_DURATION_KEY;
 52	  }
 53	
 54	  return timeRangeOptions.findIndex((option) => option.key === durationKey) ?? 1;
 55	};
 56	
 57	export const TimeRangeDropdown: React.FC<TimeRangeDropdownProps> = ({
 58	  onChange,
 59	  value,
 60	  isDisabled = false,
 61	  timezone,
 62	}) => {
 63	  const { t } = useTranslation('plugin__logging-view-plugin');
 64	
 65	  const [isTimeRangeModalOpen, setIsTimeRangeModalOpen] = React.useState(false);
 66	  const [storedTimeRange, setStoredTimeRange] = useLocalStorage<TimeRange>(STORED_TIME_RANGE_KEY);
 67	
 68	  const [isOpen, setIsOpen] = React.useState(false);
 69	  const [selectedIndex, setSelectedIndex] = React.useState<number>(
 70	    getSelectedOptionIndex({ storedTimeRange, timeRangeValue: value }),
 71	  );
 72	
 73	  React.useEffect(() => {
 74	    setSelectedIndex(getSelectedOptionIndex({ timeRangeValue: value }));
 75	  }, [value]);
 76	
 77	  const handleSelectedValue = (index: number) => () => {
 78	    setIsOpen(false);
 79	
 80	    const { key } = timeRangeOptions[index];
 81	
 82	    if (key === CUSTOM_TIME_RANGE_KEY) {
 83	      setIsTimeRangeModalOpen(true);
 84	    } else {
 85	      setSelectedIndex(index);
 86	      const timeRange = timeRangeFromDuration(timeRangeOptions[index].key);
 87	      onChange?.(timeRange);
 88	      setStoredTimeRange(timeRange);
 89	    }
 90	  };
 91	
 92	  const handleCustomRangeSelected = (customRange: TimeRange) => {
 93	    setSelectedIndex(0);
 94	    setIsTimeRangeModalOpen(false);
 95	    onChange?.(customRange);
 96	    setStoredTimeRange(customRange);
 97	  };
 98	
 99	  const toggleIsOpen = () => {
100	    setIsOpen(!isOpen);
101	  };
102	
103	  const handleCloseModal = () => {
104	    setIsTimeRangeModalOpen(false);
105	  };
106	
107	  const timeRangeValue = value ?? storedTimeRange ?? undefined;
108	
109	  return (
110	    <>
111	      {isTimeRangeModalOpen && (
112	        <TimeRangeSelectModal
113	          onClose={handleCloseModal}
114	          onSelectRange={handleCustomRangeSelected}
115	          initialRange={timeRangeValue}
116	          timezone={timezone}
117	        />
118	      )}
119	      <FormGroup fieldId="logs-time-range" data-test={TestIds.TimeRangeDropdown}>
120	        <Dropdown
121	          isOpen={isOpen}
122	          onSelect={() => setIsOpen(false)}
123	          onOpenChange={(isOpenVal: boolean) => setIsOpen(isOpenVal)}
124	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
125	            <MenuToggle
126	              isDisabled={isDisabled}
127	              ref={toggleRef}
128	              onClick={toggleIsOpen}
129	              isExpanded={isOpen}
130	            >
131	              {timeRangeOptions[selectedIndex].key === CUSTOM_TIME_RANGE_KEY && timeRangeValue
132	                ? formatTimeRange(timeRangeValue, timezone)
133	                : timeRangeOptions[selectedIndex].name}
134	            </MenuToggle>
135	          )}
136	        >
137	          <DropdownList>
138	            {timeRangeOptions.map(({ key, name }, index) => (
139	              <DropdownItem ouiaId={key} onClick={handleSelectedValue(index)} key={key}>
140	                {
141	                  /*
142	                    t('plugin__logging-view-plugin~Custom time range')
143	                    t('plugin__logging-view-plugin~Last 5 minutes')
144	                    t('plugin__logging-view-plugin~Last 15 minutes')
145	                    t('plugin__logging-view-plugin~Last 30 minutes')
146	                    t('plugin__logging-view-plugin~Last 1 hour')
147	                    t('plugin__logging-view-plugin~Last 2 hours')
148	                    t('plugin__logging-view-plugin~Last 6 hours')
149	                    t('plugin__logging-view-plugin~Last 12 hours')
150	                    t('plugin__logging-view-plugin~Last 1 day')
151	                    t('plugin__logging-view-plugin~Last 2 days')
152	                    t('plugin__logging-view-plugin~Last 1 week')
153	                    t('plugin__logging-view-plugin~Last 2 weeks')
154	                  */
155	                  t(`plugin__logging-view-plugin~${name}`)
156	                }
157	              </DropdownItem>
158	            ))}
159	          </DropdownList>
160	        </Dropdown>
161	      </FormGroup>
162	    </>
163	  );
164	};

